/**
 * @class UtilityFunctions
 * @description Provides a set of helper functions.
 * @since 19/02/2026
 * @date  19/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */
class UtilityFunctions {


    /**
     * @description Returns GlideRecord object from  specified  table and identifier
     *
     * @param {String} table The table to be used.
     * @param {String} column  Name of the instantiated GlideRecord column to search for the identifier.
     * @param {String} identifier Value to match.
     *
     * @returns {Object} GlideRecord object from  specified  table and identifier
     */
    static getRecord(table, column, identifier) {
        let record = null;
        const gr = new GlideRecord(table);

        if (gr.get(column, identifier)) {
            record = gr;
        }

        return record;
    }

    /**
     * @description Returns Glider record object based on the mention condition in the query.
     *
     * @param {String} table The table to be used.
     * @param {String} query Encoded query
     *
     * @returns {Object} GlideRecord object from  specified  table
     */
    static getGlideRecord(table, query) {
        const record = new GlideRecord(table);
        record.addEncodedQuery(query);
        record.query();

        return record;
    }

    /**
     * @description Based on the mention criteria in the query and limit, Glider record object will be return
     *
     * @param {String} table The table to be used
     * @param {String} query Encoded query
     * @param {Number} limit The maximum number of records to fetch
     *
     * @returns {Object} GlideRecord object from  specified  table
     */
    static getLimitedGlideRecord(table, query, limit) {
        const record = new GlideRecord(table);
        record.addEncodedQuery(query);
        record.setLimit(limit);
        record.query();

        return record;
    }
	/**
	 * 
	 * Converts a given value into a boolean.
	 * 
	 * @returns {Boolean} true/false
	 */
    static getBooleanValue(value) {
        const TRUE = 1;
        let booleanValue = false;

        if ((value === true) || (value === 'true') || (value === TRUE)) {
            booleanValue = true;
        }

        return booleanValue;
    }

    /**
	 * Returns the root table of a given table
	 * 
	 * @returns {String} root table name
     * 
     */
    static getBaseTable(tableName) {
        const table = new global.TableUtils(tableName);

        return table.getAbsoluteBase();
    }

    /**
 	* Return an array of table names in the table parent hierarchy
	 * 
	 * @param {String} tableName table name
	 * 
	 * @returns {ArrayList} list of table names
     */
    static getTables(tableName) {
        const table = new global.TableUtils(tableName);

        return table.getTables().toArray();
    }


    /**
     * Checks if the given table is a valid table
	 * 
	 * @param {String} tableName table name
	 * 
	 * @returns {Boolean} true/false
     */
    static isValidTable(tableName) {
        const table = new global.TableUtils(tableName);

        return table.tableExists() && !Constants.BLACK_LIST_TABLES.includes(tableName);
    }


    /**
     * Checks if the given table is a valid table
	 * 
	 * @param {String} tableName table name
	 * @param {String} query encoded query
	 * 
	 * @returns {Boolean} true/false
     */
    static isValidRecord(tableName, query) {
        const LIMIT = 1;
        let valid = false;

        const record = new GlideRecord(tableName);

        record.addEncodedQuery(query);
        record.setLimit(LIMIT);
        record.query();

        if (record.next()) {
            valid = true;
        }

        return valid;
    }
}
